code = """import json

# Load the analysis results
top_cpc_results = locals()['var_functions.execute_python:52']
titles_data = locals()['var_functions.query_db:56']

# Parse the JSON results
top_cpc = top_cpc_results['top_10_cpc']
titles = {item['symbol']: item['titleFull'] for item in titles_data}

# Create final results with titles
final_results = []
for cpc_code, data in top_cpc:
    final_results.append({
        'cpc_group_code': cpc_code,
        'full_title': titles.get(cpc_code, 'Title not found'),
        'best_year': data['year'],
        'ema_value': round(data['ema_value'], 2),
        'raw_patent_count': data['raw_count']
    })

# Count how many had best year in 2019 (second half)
count_2019 = sum(1 for r in final_results if r['best_year'] == 2019)

print('__RESULT__:')
print(json.dumps({
    'summary': {
        'total_cpc_groups_analyzed': len(final_results),
        'groups_with_best_year_2019': count_2019,
        'groups_with_best_year_other': len(final_results) - count_2019
    },
    'top_cpc_groups': final_results
}, indent=2))"""

